export function initialize(element, dotNetRef, timeoutMs) {
    const state = { timerId: null, isIdle: false };

    function resetTimer() {
        clearTimeout(state.timerId);
        if (state.isIdle) {
            state.isIdle = false;
            dotNetRef.invokeMethodAsync('OnUserActive');
        }
        state.timerId = setTimeout(() => {
            state.isIdle = true;
            dotNetRef.invokeMethodAsync('OnUserIdle');
        }, timeoutMs);
    }

    const events = ['mousemove', 'keydown', 'click', 'scroll'];
    events.forEach(e => element.addEventListener(e, resetTimer));

    // Start the initial timer
    resetTimer();

    return {
        dispose: () => {
            clearTimeout(state.timerId);
            events.forEach(e => element.removeEventListener(e, resetTimer));
        },
        updateTimeout: (newTimeoutMs) => {
            timeoutMs = newTimeoutMs;
            resetTimer();
        }
    };
}

